<template><div v-if="app"><el-card><template #header><div class="head"><b>{{app.applicationNo}}</b><div><el-button v-if="app.status==='DRAFT'&&user.hasPermission('application:submit')" type="primary" @click="submit">提交审批</el-button><el-button v-if="app.status==='UNDER_REVIEW'&&user.hasPermission('application:withdraw')" type="warning" @click="withdraw">撤回</el-button></div></div></template><el-descriptions :column="2" border><el-descriptions-item label="标题">{{app.title}}</el-descriptions-item><el-descriptions-item label="状态">{{app.status}}</el-descriptions-item><el-descriptions-item label="业务类型">{{app.businessType}}</el-descriptions-item><el-descriptions-item label="申请人">{{app.applicantName}}</el-descriptions-item><el-descriptions-item label="原因" :span="2">{{app.reason}}</el-descriptions-item></el-descriptions></el-card>
<el-card class="section"><template #header><b>申请材料</b></template><el-upload v-if="app.status==='DRAFT'&&user.hasPermission('material:upload')" :http-request="upload" :show-file-list="false" accept=".pdf,.jpg,.jpeg,.png"><el-button type="primary" :loading="uploading">上传必需材料</el-button></el-upload><el-progress v-if="uploading" :percentage="progress"/><el-table :data="materials"><el-table-column prop="materialName" label="材料"/><el-table-column prop="originalFilename" label="文件名"/><el-table-column prop="verifyStatus" label="核验状态"/><el-table-column prop="fileSize" label="字节数"/></el-table></el-card>
<el-card class="section"><template #header><b>审批时间线</b></template><el-timeline><el-timeline-item v-for="l in logs" :key="l.logId" :timestamp="l.operationTime">{{l.action}}：{{l.fromStatus||'-'}} → {{l.toStatus}} {{l.comment||''}}</el-timeline-item></el-timeline></el-card></div></template>
<script setup>import{onMounted,ref}from'vue';import{useRoute}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{getApplication,listMaterials,getApprovalLogs,uploadMaterial,submitApplication,withdrawApplication}from'../../api/applications';import{useUserStore}from'../../stores/user';const route=useRoute(),user=useUserStore(),app=ref(),materials=ref([]),logs=ref([]),uploading=ref(false),progress=ref(0);async function load(){[app.value,materials.value,logs.value]=await Promise.all([getApplication(route.params.id),listMaterials(route.params.id),getApprovalLogs(route.params.id)])}async function upload({file}){const data=new FormData();data.append('materialType','PROOF');data.append('materialName',file.name);data.append('requiredFlag','true');data.append('file',file);uploading.value=true;try{await uploadMaterial(route.params.id,data,e=>progress.value=Math.round(e.loaded*100/e.total));ElMessage.success('上传成功');await load()}finally{uploading.value=false}}async function submit(){await ElMessageBox.confirm('确认提交后将不能普通编辑材料，是否继续？');await submitApplication(route.params.id);ElMessage.success('已提交');load()}async function withdraw(){await ElMessageBox.confirm('确认撤回申请？');await withdrawApplication(route.params.id);ElMessage.success('已撤回');load()}onMounted(load)</script><style scoped>.head{display:flex;justify-content:space-between}.section{margin-top:16px}</style>
